head.script:
// 전역변수 세팅
scwin.userId = "";
scwin.crryinoutClsCd ="";
scwin.onoffNo = "";
scwin.lblock  = "";
scwin.reqWrkDt = "";
scwin.s_query_date = "";
scwin.s_query_mch = "";
scwin.eqCd = "";
scwin.wrkPlCd = "";
scwin.lobranCd = "";
scwin.fullEmptyClsCd = "";
scwin.selfClsCd = "";
scwin.orgLineCd = "";
scwin.orgCntrSt = "";
scwin.g_selected_input_box = "";
scwin.g_selected_f_Check = "0";
scwin.checkFixCntrNo = "0";
scwin.pgrId;
scwin.cntrNo;
scwin.condWrkDt;


scwin.onpageload = async function() {

    scwin.initSetting();

    if(scwin.wrkPlCd == "" || scwin.eqCd == "" || scwin.lobranCd == ""){ 
        let loginData = scwin.getCYLoginData();
        if(loginData != null) {
            scwin.wrkPlCd = loginData.wrkPlCd ?? "";
            scwin.lobranCd = loginData.lobranCd ?? "";
            scwin.eqCd = loginData.eqCd ?? "";
        }
    }

    if (scwin.lobranCd == "" || scwin.eqCd == "" || scwin.wrkPlCd == "") {

		let strUrl = "/ui/tn/op/transwrkindict/cntr/tn_304_03_01b.xml";
		let programId = scwin.pgrId;

		let params = {
			pgrId: scwin.pgrId
		}

		let loginMenuNm = "CY자동화로그인";
		$c.win.openMenu(loginMenuNm, strUrl, programId, params, { openAction: "exist", mdiTitle: loginMenuNm });

		//확인필요
		//response.sendRedirect("/tn/op/transwrkindict/cntr/tn_304_03_01b.xml");
		//
		//location.href("/tn/op/transwrkindict/cntr/tn_304_03_01b.xml")
	}
    // 로직 시작
    ed_cntrNo.focus();


    ds_condition.set("onoffNo", scwin.onoffNo);
    ds_condition.set("crryinoutClsCd", scwin.crryinoutClsCd);
    ds_wrkInfo.set("onoffNo", scwin.onoffNo);

    if(!$c.gus.cfIsNull(scwin.onoffNo)){

        await scwin.f_retrieve();
    }

    var crryinoutIntendNo = ds_outInfo.getCellData(0, "crryinoutIntendNo") == null ? "": ds_outInfo.getCellData(0, "crryinoutIntendNo");
    var cntrNo = ds_outInfo.getCellData(0, "cntrNo") == null ? "" : ds_outInfo.getCellData(0, "cntrNo");
    var regId = ds_outInfo.getCellData(0, "regId") == null ? "" : ds_outInfo.getCellData(0, "regId");
    var modId = ds_outInfo.getCellData(0, "modId") == null ? "" : ds_outInfo.getCellData(0, "modId");

    if(scwin.onoffNo != "" && cntrNo == "" && crryinoutIntendNo == "" && (regId == "kdclc020" || modId == "kdclc020")){
        btn_delete.show();
    };


};

scwin.getCYLoginData = function() {
    var raw = localStorage.getItem("CY_LOGIN_INFO");
    if (!raw) return null;

    try {
        return JSON.parse(decodeURIComponent(escape(atob(raw))));
    } catch (e) {
        return null;
    }
};


scwin.initSetting = function(){

    scwin.param = $c.data.getParameter();

    scwin.userId = $c.data.getMemInfo("userId");
    scwin.crryinoutClsCd = scwin.param.crryinoutClsCd ==null? "" : scwin.param.crryinoutClsCd;
    scwin.onoffNo = scwin.param.onoffNo ==null? "" : scwin.param.onoffNo;
    scwin.lblock = scwin.param.lblock ==null? "" : scwin.param.lblock;
    scwin.reqWrkDt = scwin.param.reqWrkDt ==null? "" :scwin.param.reqWrkDt ;
    scwin.s_query_date = scwin.param.s_query_date ==null? "" : scwin.param.s_query_date ;
    scwin.s_query_mch = scwin.param.s_query_mch ==null? "" : scwin.param.s_query_mch ;
    scwin.eqCd = scwin.param.eqCd == null? "" : scwin.param.eqCd ;
    scwin.wrkPlCd = scwin.param.wrkPlCd == null? "" : scwin.param.wrkPlCd ;
    scwin.lobranCd = scwin.param.lobranCd == null? "" : scwin.param.lobranCd ;
    scwin.fullEmptyClsCd = scwin.param.fullEmptyClsCd ==null? "" : scwin.param.fullEmptyClsCd ;
    scwin.selfClsCd =scwin.param.selfClsCd ==null? "" : scwin.param.selfClsCd ;
    scwin.g_selected_input_box = ed_cntrNo.getValue();
    scwin.cntrNo = scwin.param.cntrNo ==null? "" : scwin.param.cntrNo ;
    scwin.condWrkDt = scwin.param.condWrkDt == null?"": scwin.param.condWrkDt;
    scwin.pgrId = $c.data.getParameter("pgrId") == null? "tn_304_03_03b" : $c.data.getParameter($p, "pgrId") ;

    ed_cntrNo.setValue(scwin.cntrNo);


};
scwin.f_retrieve = async function(){

    ds_condition.set("onoffNo", scwin.onoffNo);
    ds_condition.set("crryinoutClsCd", scwin.crryinoutClsCd);
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_completeWrk = async function (e) { //
   // scwin.f_twinkleBtn("complete", 80);
    if(ed_cntrNo.getValue().length != 11){
        $c.gus.cfAlertMsg("유효한 컨테이너번호를 입력하십시오");
        return
    };

    let confirm = await $c.win.confirm("작업을 완료 하시겠습니까?");
    if(confirm) {

        ds_outInfo.setCellData( 0, "crryinoutIntendNo", scwin.crryinoutClsCd);
        scwin.tr_save();
    };
};

scwin.tr_save = function(){
    ds_outInfo.setCellData(0 ,"vehclNo", ed_vehclNo.getValue());
    ds_outInfo.setCellData(0 ,"crryinoutClsCd", ed_crryinoutClsCd.getValue());
    ds_outInfo.setCellData(0 ,"cntrSt", ed_cntrSt.getValue());
    ds_outInfo.setCellData(0 ,"cntrNo", ed_cntrNo.getValue());
    ds_outInfo.setCellData(0 ,"lineCd", ed_lineCd.getValue());
    ds_outInfo.setCellData(0 ,"fullEmptyClsCd", ed_fullEmptyClsCd.getValue());
    ds_outInfo.setCellData(0 ,"indcLblock ", ed_indcLblock .getValue());
    ds_outInfo.setCellData(0 ,"lrow", ed_lrow.getValue());
    ds_outInfo.setCellData(0 ,"ltier", ed_ltier.getValue());
    ds_outInfo.setCellData(0 ,"wrkMemo", ed_wrkMemo.getValue());
    ds_outInfo.setCellData(0 ,"odrKndCd", ed_odrKndCd.getValue());
    ds_outInfo.setCellData(0 ,"chgCntrNo", ed_chgCntrNo.getValue());




    $c.sbm.execute(sbm_save);
}

scwin.f_back = function (e) {

    let strUrl = "/ui/tn/op/transwrkindict/cntr/tn_304_03_02b.xml";
    let programId = scwin.pgrId;
    let paramObj = {
        wrkPlCd : scwin.wrkPlCd
      , eqCd : scwin.eqCd
      , lobranCd : scwin.lobranCd
      , lblock : scwin.lblock
      , reqWrkDt : scwin.reqWrkDt
      , fullEmptyClsCd : scwin.fullEmptyClsCd
      , selfClsCd : scwin.selfClsCd
      , pgrId : scwin.pgrId
      , condWrkDt : scwin.condWrkDt
    };
    $c.win.openMenu("CY 상하차정보조회(R/S)", strUrl, programId, paramObj, {openAction: "exist"});
};

